from vex_sdk import VexGuardrail, GuardrailResult
from google.adk import Agent

@VexGuardrail(name="tenant-isolation")
def check_tenant_isolation(ctx: dict) -> GuardrailResult:
    tenant_id = ctx.get('session', {}).get('tenant_id')
    current_agent_tenant = ctx.get('agent_config', {}).get('tenant_id')

    if tenant_id != current_agent_tenant:
        return GuardrailResult(
            passed=False,
            violation="Tenant isolation breach: session tenant {} != agent tenant {}".format(tenant_id, current_agent_tenant),
            metadata={'expected_tenant': tenant_id, 'actual_tenant': current_agent_tenant}
        )
    return GuardrailResult(passed=True)

# Integration in ADK
agent = Agent(
    before_agent_callback=[check_tenant_isolation],
    # ... other config
)

from vex_sdk import VexGuardrail, GuardrailResult
from collections import deque

@VexGuardrail(name="circular-dependency")
def detect_circular_dependency(ctx: dict) -> GuardrailResult:
    session_history = ctx.get('session', {}).get('agent_call_stack', [])
    current_agent = ctx.get('agent_id')

    # Track last 10 calls to detect loops
    recent_calls = deque(session_history[-10:], maxlen=10)
    if len(recent_calls) > 1 and recent_calls[0] == current_agent:
        return GuardrailResult(
            passed=False,
            violation="Circular dependency detected: {} called itself".format(current_agent),
            metadata={'call_stack': list(recent_calls)}
        )

    # Update stack
    session_history.append(current_agent)
    ctx['session']['agent_call_stack'] = session_history[-20:]  # Limit size
    return GuardrailResult(passed=True)

from vex_sdk import VexGuardrail, GuardrailResult

TENANT_REGIONS = {
    'tenant_a': 'eu-west-1',
    'tenant_b': 'us-east-1'
}

@VexGuardrail(name="data-residency")
def enforce_data_residency(ctx: dict) -> GuardrailResult:
    tenant_id = ctx.get('session', {}).get('tenant_id')
    model_region = ctx.get('model_config', {}).get('region')
    required_region = TENANT_REGIONS.get(tenant_id)

    if required_region and model_region != required_region:
        return GuardrailResult(
            passed=False,
            violation="Data residency violation: tenant {} requires {}, got {}".format(tenant_id, required_region, model_region),
            metadata={'tenant': tenant_id, 'required': required_region, 'actual': model_region},
            remediation="Route to {} Gemini endpoint".format(required_region)
        )
    return GuardrailResult(passed=True)

# ADK Integration
agent.before_agent_callback.append(enforce_data_residency)
